  "inlineSchema": "// Prisma schema for Healthcare Appointment Manager\n// Uses MySQL connector (TiDB is MySQL wire-compatible)\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── Users (shared auth table) ───────────────────────────────────────────────\n\nmodel User {\n  id           Int      @id @default(autoincrement())\n  email        String   @unique @db.VarChar(255)\n  passwordHash String   @map(\"password_hash\") @db.VarChar(255)\n  role         UserRole\n  fullName     String   @map(\"full_name\") @db.VarChar(255)\n  phone        String?  @db.VarChar(20)\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n\n  // Google Calendar OAuth tokens (encrypted)\n  googleRefreshToken String? @map(\"google_refresh_token\") @db.Text\n\n  // Relations\n  doctorProfile       Doctor?\n  appointments        Appointment[]        @relation(\"PatientAppointments\")\n  notifications       Notification[]\n  medicationReminders MedicationReminder[]\n\n  @@map(\"users\")\n}\n\nenum UserRole {\n  admin\n  doctor\n  patient\n}\n\n// ─── Doctor profile (1:1 with users where role='doctor') ─────────────────────\n\nmodel Doctor {\n  id              Int      @id @default(autoincrement())\n  userId          Int      @unique @map(\"user_id\")\n  specialisation  String   @db.VarChar(120)\n  slotDurationMin Int      @default(15) @map(\"slot_duration_min\")\n  workingHours    Json     @map(\"working_hours\") // {\"mon\":[\"10:00\",\"17:00\"], ...}\n  consultationFee Decimal? @map(\"consultation_fee\") @db.Decimal(10, 2)\n\n  // Relations\n  user         User          @relation(fields: [userId], references: [id])\n  leaves       DoctorLeave[]\n  appointments Appointment[]\n\n  @@index([specialisation], name: \"idx_specialisation\")\n  @@map(\"doctors\")\n}\n\n// ─── Doctor leave days ───────────────────────────────────────────────────────\n\nmodel DoctorLeave {\n  id        Int      @id @default(autoincrement())\n  doctorId  Int      @map(\"doctor_id\")\n  leaveDate DateTime @map(\"leave_date\") @db.Date\n  reason    String?  @db.VarChar(255)\n\n  // Relations\n  doctor Doctor @relation(fields: [doctorId], references: [id])\n\n  @@unique([doctorId, leaveDate], name: \"uq_doctor_leave\")\n  @@map(\"doctor_leaves\")\n}\n\n// ─── Appointments ────────────────────────────────────────────────────────────\n\nmodel Appointment {\n  id                   Int               @id @default(autoincrement())\n  doctorId             Int               @map(\"doctor_id\")\n  patientId            Int               @map(\"patient_id\")\n  slotStart            DateTime          @map(\"slot_start\")\n  slotEnd              DateTime          @map(\"slot_end\")\n  status               AppointmentStatus @default(held)\n  holdExpiresAt        DateTime?         @map(\"hold_expires_at\")\n  googleEventIdPatient String?           @map(\"google_event_id_patient\") @db.VarChar(255)\n  googleEventIdDoctor  String?           @map(\"google_event_id_doctor\") @db.VarChar(255)\n  createdAt            DateTime          @default(now()) @map(\"created_at\")\n\n  // Relations\n  doctor      Doctor       @relation(fields: [doctorId], references: [id])\n  patient     User         @relation(\"PatientAppointments\", fields: [patientId], references: [id])\n  symptomForm SymptomForm?\n  visitNote   VisitNote?\n\n  @@unique([doctorId, slotStart, status], name: \"uq_doctor_slot_confirmed\")\n  @@map(\"appointments\")\n}\n\nenum AppointmentStatus {\n  held\n  confirmed\n  cancelled\n  completed\n  leave_cancelled\n}\n\n// ─── Pre-visit symptom form + AI summary ─────────────────────────────────────\n\nmodel SymptomForm {\n  id                 Int           @id @default(autoincrement())\n  appointmentId      Int           @unique @map(\"appointment_id\")\n  rawSymptoms        String        @map(\"raw_symptoms\") @db.Text\n  durationDays       Int?          @map(\"duration_days\")\n  severity           Severity?\n  urgencyLevel       UrgencyLevel? @map(\"urgency_level\")\n  chiefComplaint     String?       @map(\"chief_complaint\") @db.VarChar(255)\n  suggestedQuestions Json?         @map(\"suggested_questions\")\n  aiStatus           AiStatus      @default(pending) @map(\"ai_status\")\n  createdAt          DateTime      @default(now()) @map(\"created_at\")\n\n  // Relations\n  appointment Appointment @relation(fields: [appointmentId], references: [id])\n\n  @@map(\"symptom_forms\")\n}\n\nenum Severity {\n  mild\n  moderate\n  severe\n}\n\nenum UrgencyLevel {\n  Low\n  Medium\n  High\n}\n\nenum AiStatus {\n  pending\n  ok\n  failed\n}\n\n// ─── Post-visit notes, prescription, AI patient summary ──────────────────────\n\nmodel VisitNote {\n  id             Int      @id @default(autoincrement())\n  appointmentId  Int      @unique @map(\"appointment_id\")\n  clinicalNotes  String   @map(\"clinical_notes\") @db.Text\n  prescription   Json // [{drug, dosage, frequency, duration_days}]\n  patientSummary String?  @map(\"patient_summary\") @db.Text\n  aiStatus       AiStatus @default(pending) @map(\"ai_status\")\n  createdAt      DateTime @default(now()) @map(\"created_at\")\n\n  // Relations\n  appointment         Appointment          @relation(fields: [appointmentId], references: [id])\n  medicationReminders MedicationReminder[]\n\n  @@map(\"visit_notes\")\n}\n\n// ─── Medication reminder schedule ────────────────────────────────────────────\n\nmodel MedicationReminder {\n  id          Int      @id @default(autoincrement())\n  visitNoteId Int      @map(\"visit_note_id\")\n  patientId   Int      @map(\"patient_id\")\n  drugName    String   @map(\"drug_name\") @db.VarChar(255)\n  scheduledAt DateTime @map(\"scheduled_at\")\n  sent        Boolean  @default(false)\n\n  // Relations\n  visitNote VisitNote @relation(fields: [visitNoteId], references: [id])\n  patient   User      @relation(fields: [patientId], references: [id])\n\n  @@index([scheduledAt, sent], name: \"idx_scheduled_pending\")\n  @@map(\"medication_reminders\")\n}\n\n// ─── Notification log + retry tracking ───────────────────────────────────────\n\nmodel Notification {\n  id        Int                 @id @default(autoincrement())\n  userId    Int                 @map(\"user_id\")\n  type      NotificationType\n  channel   NotificationChannel\n  status    NotificationStatus  @default(queued)\n  payload   Json? // email subject/body, event details, etc.\n  attempts  Int                 @default(0)\n  lastError String?             @map(\"last_error\") @db.Text\n  createdAt DateTime            @default(now()) @map(\"created_at\")\n\n  // Relations\n  user User @relation(fields: [userId], references: [id])\n\n  @@index([status, attempts], name: \"idx_status_attempts\")\n  @@map(\"notifications\")\n}\n\nenum NotificationType {\n  booking_confirmation\n  reminder\n  cancellation\n  leave_notice\n  medication\n}\n\nenum NotificationChannel {\n  email\n  calendar\n}\n\nenum NotificationStatus {\n  queued\n  sent\n  failed\n}\n",
